import sys
import ast
import itertools

# ---------- scoring helpers ----------
BASE = {1: 1000, 2: 200, 3: 300, 4: 400, 5: 500, 6: 600}


def get_score(dice):
    """Return maximal score for a single roll or the string 'Zonk'."""
    # frequency of each face, index 0 unused
    cnt = [0] * 7
    for d in dice:
        cnt[d] += 1

    best = 0                     # best score found so far

    def dfs(cnt, cur):
        nonlocal best
        # record current score (stop here)
        if cur > best:
            best = cur

        # ----- straight (1‑6) -----
        if all(cnt[i] >= 1 for i in range(1, 7)):
            for i in range(1, 7):
                cnt[i] -= 1
            dfs(cnt, cur + 1500)
            for i in range(1, 7):
                cnt[i] += 1

        # ----- three pairs -----
        faces = [i for i in range(1, 7) if cnt[i] >= 2]
        if len(faces) >= 3:
            for combo in itertools.combinations(faces, 3):
                for i in combo:
                    cnt[i] -= 2
                dfs(cnt, cur + 750)
                for i in combo:
                    cnt[i] += 2

        # ----- 3,4,5,6 of a kind -----
        for val in range(1, 7):
            for k in (6, 5, 4, 3):
                if cnt[val] >= k:
                    # multiplier: 3->1, 4->2, 5->3, 6->4  => (k-2)
                    points = (k - 2) * BASE[val]
                    cnt[val] -= k
                    dfs(cnt, cur + points)
                    cnt[val] += k

        # ----- single 1 -----
        if cnt[1] >= 1:
            cnt[1] -= 1
            dfs(cnt, cur + 100)
            cnt[1] += 1

        # ----- single 5 -----
        if cnt[5] >= 1:
            cnt[5] -= 1
            dfs(cnt, cur + 50)
            cnt[5] += 1

    dfs(cnt, 0)

    return "Zonk" if best == 0 else best


# ---------- I/O ----------
def read_dice():
    """
    Read a single line from stdin and convert it to a list of integers.
    Accepts:
      - Python literal list/tuple:   [1,2,3]
      - Space/comma separated numbers: 1 2 3 4 5 6
    """
    line = sys.stdin.readline()
    if not line:
        return []

    line = line.strip()

    # Try to interpret the whole line as a Python literal (list/tuple/int)
    try:
        parsed = ast.literal_eval(line)
        if isinstance(parsed, (list, tuple)):
            return list(parsed)
        if isinstance(parsed, int):
            return [parsed]
    except Exception:
        pass

    # Fallback: treat the line as a sequence of numbers separated by
    # spaces or commas.
    for ch in '[],':          # remove brackets and commas
        line = line.replace(ch, ' ')
    return [int(tok) for tok in line.split() if tok]


def main():
    dice = read_dice()
    result = get_score(dice)
    print(result)


if __name__ == "__main__":
    main()

