def drop_cap(s: str) -> str:
    result = []
    cur = []
    for ch in s:
        if ch == ' ':
            if cur:
                word = ''.join(cur)
                if len(word) > 2:
                    word = word[0].upper() + word[1:].lower()
                result.append(word)
                cur = []
            result.append(ch)
        else:
            cur.append(ch)
    if cur:
        word = ''.join(cur)
        if len(word) > 2:
            word = word[0].upper() + word[1:].lower()
        result.append(word)
    return ''.join(result)

