import sys

def neighbours(ch: str) -> set:
    """Return the set of characters that `ch` can be changed into."""
    if ch == 'a':
        return {'b'}
    if ch == 'z':
        return {'y'}
    # any other character can become its predecessor or successor
    return {chr(ord(ch) - 1), chr(ord(ch) + 1)}


def can_form_palindrome(st: str) -> bool:
    """
    Return True if at least one way of changing every character
    (to its predecessor or successor) can produce a palindrome.
    """
    n = len(st)
    for i in range(n // 2):
        left_opts = neighbours(st[i])
        right_opts = neighbours(st[n - 1 - i])
        # If the two sets have no common element, a palindrome is impossible
        if not (left_opts & right_opts):
            return False
    # All symmetric pairs have at least one matching option
    return True


def solve(st: str) -> bool:
    """Required interface: return a boolean, not a string."""
    return can_form_palindrome(st)


def main() -> None:
    s = sys.stdin.readline().strip()
    print(solve(s))


if __name__ == "__main__":
    main()

import sys
import math

def solution(value):
    """
    Round `value` to the nearest 0.5 step (half‑up) and return the result
    as a string.  The string is either an integer without a decimal point
    (e.g. "4") or ends with ".5" (e.g. "4.5").
    """
    # Accept numbers or numeric strings
    try:
        x = float(value)
    except (TypeError, ValueError):
        raise ValueError("Input must be a numeric value")

    # Round‑half‑up to the nearest 0.5
    rounded = math.floor(x * 2 + 0.5) / 2

    # Always return a string – required for the test harness
    if rounded.is_integer():
        # Whole number: no decimal part
        return str(int(rounded))
    else:
        # Half step: keep exactly one decimal place (".5")
        return "{:.1f}".format(rounded)

