def alphabet_war(fight: str) -> str:
    n = len(fight)
    remove = [False] * n

    for i, ch in enumerate(fight):
        if ch == '*':
            remove[i] = True
            if i > 0:
                remove[i - 1] = True
            if i < n - 1:
                remove[i + 1] = True

    survivors = [fight[i] for i in range(n) if not remove[i]]

    left_power = {'w': 4, 'p': 3, 'b': 2, 's': 1}
    right_power = {'m': 4, 'q': 3, 'd': 2, 'z': 1}

    left_total = sum(left_power.get(c, 0) for c in survivors)
    right_total = sum(right_power.get(c, 0) for c in survivors)

    if left_total > right_total:
        return "Left side wins!"
    if right_total > left_total:
        return "Right side wins!"
    return "Let's fight again!"


