def forward(ch, steps):
    idx = ord(ch) - ord('a')
    new_idx = (idx + steps) % 26
    return chr(new_idx + ord('a'))

def backward(ch, steps):
    idx = ord(ch) - ord('a')
    new_idx = (idx - steps) % 26
    return chr(new_idx + ord('a'))

def transform(s):
    vowels = {'a', 'e', 'i', 'o', 'u'}
    exception_shifts = {'c': 1, 'o': 1, 'd': 3, 'e': 4}
    exception_letters = set(exception_shifts.keys())
    result = []
    for ch in s:
        if ch in exception_shifts:
            tentative = backward(ch, exception_shifts[ch])
            final = ch if tentative in exception_letters else tentative
        else:
            if ch in vowels:
                tentative = backward(ch, 5)
            else:
                tentative = forward(ch, 9)
            final = ch if tentative in exception_letters else tentative
        result.append(final)
    return ''.join(result)

s = input().strip()
print(transform(s))

import sys

def transform_sentence(sentence: str) -> str:
    if not sentence:
        return ""
    punct_set = set('.,!?:;,')

    tokens = sentence.split()
    result = []

    for token in tokens:
        # Separate trailing punctuation
        core_end = len(token)
        while core_end > 0 and token[core_end - 1] in punct_set:
            core_end -= 1
        core = token[:core_end]
        punct = token[core_end:]

        # Rule 1: reverse if length > 6 or >=2 t/T
        t_count = sum(1 for ch in core if ch in ('t', 'T'))
        if len(core) > 6 or t_count >= 2:
            new_core = core[::-1]
        else:
            # Rule 2: uppercase if length == 2 or before a comma
            if len(core) == 2 or (',' in punct):
                new_core = core.upper()
            else:
                # Rule 3: replace single character with "0"
                if len(core) == 1:
                    new_core = '0'
                else:
                    new_core = core
        result.append(new_core + punct)

    return ' '.join(result)

def main():
    data = sys.stdin.read()
    # Preserve possible leading/trailing newlines but strip only the final newline for processing
    sentence = data.rstrip('\n')
    output = transform_sentence(sentence)
    print(output)

