import re

def gymSlang(text: str) -> str:
    mapping = {
        "probably": "prolly",
        "i am": "i'm",
        "instagram": "insta",
        "do not": "don't",
        "going to": "gonna",
        "combination": "combo"
    }

    def repl_factory(slang):
        def repl(m):
            if m.group(0)[0].isupper():
                return slang.capitalize()
            return slang
        return repl

    for orig, slang in mapping.items():
        # lowercase pattern
        pattern_low = re.compile(r'\b' + re.escape(orig) + r'\b')
        text = pattern_low.sub(repl_factory(slang), text)

        # capitalized pattern (first letter of each word uppercase)
        cap_orig = orig.title()
        pattern_cap = re.compile(r'\b' + re.escape(cap_orig) + r'\b')
        text = pattern_cap.sub(repl_factory(slang), text)

    return text

