def is_madhav(arr):
    n = len(arr)
    if n <= 1:
        return False

    total = 1
    group = 2
    while total + group <= n:
        total += group
        group += 1
    k = group - 1

    if total != n:
        return False

    target = arr[0]
    pos = 1
    for size in range(2, k + 1):
        if sum(arr[pos:pos + size]) != target:
            return False
        pos += size
    return True

