    upper_vowels = {'A', 'E', 'I', 'O', 'U'}
    lower_vowels = {'a', 'e', 'i', 'o', 'u'}
    out = []
    for c in s:
        if c in upper_vowels:
            out.append("Iron Yard")
        elif c.isupper() and c.isalpha():
            out.append("Iron")
