import sys

MAX_LEN = 25

def next_polydivisible(n: int):
    if n < 0:
        n = 0
    s = str(n)
    L = len(s)

    # recursive search
    sys.setrecursionlimit(10000)

    def dfs(pos: int, cur: int, larger: bool, target_len: int):
        # lower bound for this digit
        if pos == 1:
            lower = 1
        elif not larger and pos <= L:
            lower = int(s[pos - 1])
        else:
            lower = 0

        for d in range(lower, 10):
            new_val = cur * 10 + d
            if new_val % pos != 0:
                continue
            new_larger = larger or (pos <= L and d > int(s[pos - 1]))
            if pos == target_len:
                if new_larger:
                    return new_val
                continue
            res = dfs(pos + 1, new_val, new_larger, target_len)
            if res is not None:
                return res
        return None

    for length in range(L, MAX_LEN + 1):
        start_larger = length > L
        ans = dfs(1, 0, start_larger, length)
        if ans is not None:
            return ans
    return None


def main():
    data = sys.stdin.read().strip()
    if not data:
        return
    n = int(data)
    result = next_polydivisible(n)
    if result is None:
        print("None")
    else:
        print(result)


