VOWEL_SET = set('aeiou')

def solve_word(s: str) -> str:
    vowels = [ch for ch in s if ch in VOWEL_SET]
    cons = [ch for ch in s if ch not in VOWEL_SET]

    if abs(len(vowels) - len(cons)) > 1:
        return "failed"

    # decide which type must start
    if len(vowels) >= len(cons):   # also covers equal case (must start with vowel)
        start = 'vowel'
    else:
        start = 'consonant'

    vowels.sort()
    cons.sort()

    i = j = 0
    res = []
    while i < len(vowels) or j < len(cons):
        if start == 'vowel':
            if i < len(vowels):
                res.append(vowels[i])
                i += 1
            if j < len(cons):
                res.append(cons[j])
                j += 1
        else:  # start with consonant
            if j < len(cons):
                res.append(cons[j])
                j += 1
            if i < len(vowels):
                res.append(vowels[i])
                i += 1

    return ''.join(res)


