def age_stats(ages):
    if not ages:
        raise ValueError("Age list must contain at least one element.")
    youngest = oldest = ages[0]
    for age in ages[1:]:
        if age < youngest:
            youngest = age
        if age > oldest:
            oldest = age
    return (youngest, oldest, oldest - youngest)


