def is_prime(k: int) -> bool:
    if k < 2:
        return False
    if k == 2:
        return True
    if k % 2 == 0:
        return False
    limit = int(math.isqrt(k))
    d = 3
    while d <= limit:
        if k % d == 0:
            return False
        d += 2
    return True

def is_mersenne_prime(n: int) -> bool:
    if n < 2:
        return False
    if n == 2:
        return True
    if not is_prime(n):
        return False

    M = (1 << n) - 1          # 2**n - 1
    s = 4
    for _ in range(n - 2):
        s = (s * s - 2) % M
    return s == 0

def main() -> None:
    data = sys.stdin.read().strip()
    if not data:
        return
    n = int(data)
    print(is_mersenne_prime(n))

