import sys

def solve_expression(expr: str) -> int:
    expr = expr.strip()
    eq_pos = expr.find('=')
    left = expr[:eq_pos]

    # find main operator, skipping possible leading minus of first operand
    start = 1 if left and left[0] == '-' else 0
    op_pos = -1
    for i in range(start, len(left)):
        if left[i] in '+-*':
            op_pos = i
            break

    op = left[op_pos]
    s1 = left[:op_pos]
    s2 = left[op_pos + 1:]
    s3 = expr[eq_pos + 1:]

    used = {int(ch) for ch in expr if ch.isdigit()}

    def ok(num: str) -> bool:
        if not num:
            return False
        if num[0] == '-':
            # negative number, allow "-0"? not allowed because leading zero after '-'
            return not (len(num) > 2 and num[1] == '0')
        else:
            return not (len(num) > 1 and num[0] == '0')

    def test(d: int) -> bool:
        ds = str(d)
        a_str = s1.replace('?', ds)
        b_str = s2.replace('?', ds)
        c_str = s3.replace('?', ds)

        if not (ok(a_str) and ok(b_str) and ok(c_str)):
            return False

        a = int(a_str)
        b = int(b_str)
        c = int(c_str)

        if op == '+':
            return a + b == c
        if op == '-':
            return a - b == c
        if op == '*':
            return a * b == c
        return False

    answer = None
    for d in range(10):
        if d in used:
            continue
        if test(d):
            answer = d
            break

    return -1 if answer is None else answer


if __name__ == "__main__":
    expression = sys.stdin.readline()
    result = solve_expression(expression)
    print(result)

import sys

def simplify(expr: str) -> str:
    i, n = 0, len(expr)
    terms = []
    while i < n:
        sign = '+'
        if expr[i] in '+-':
            sign = expr[i]
            i += 1
        start = i
        while i < n and expr[i] not in '+-':
            i += 1
        raw = expr[start:i]
        if raw:
            terms.append((sign, raw))

    coeffs = {}
    for sign, raw in terms:
        mult = 1 if sign == '+' else -1
        j = 0
        while j < len(raw) and raw[j].isdigit():
            j += 1
        if j:
            num = int(raw[:j])
        else:
            num = 1
        coef = mult * num
        var_part = raw[j:]
        key = ''.join(sorted(var_part))
        coeffs[key] = coeffs.get(key, 0) + coef

    # remove zero coefficients
    coeffs = {k: v for k, v in coeffs.items() if v != 0}
    if not coeffs:
        return "0"

    items = [(len(k), k, v) for k, v in coeffs.items()]
    items.sort(key=lambda x: (x[0], x[1]))

    out_parts = []
    for _, key, coef in items:
        sign = '-' if coef < 0 else '+'
        abs_coef = abs(coef)
        coef_str = '' if abs_coef == 1 else str(abs_coef)
        term = coef_str + key
        if not out_parts:
            if sign == '-':
                out_parts.append('-' + term)
            else:
                out_parts.append(term)
        else:
            out_parts.append(sign + term)

    return ''.join(out_parts)

def main():
    expr = sys.stdin.readline().strip()
    print(simplify(expr))

