def mix(s1: str, s2: str) -> str:
    cnt1 = [0] * 26
    cnt2 = [0] * 26

    for ch in s1:
        if 'a' <= ch <= 'z':
            cnt1[ord(ch) - 97] += 1
    for ch in s2:
        if 'a' <= ch <= 'z':
            cnt2[ord(ch) - 97] += 1

    groups = []
    for i in range(26):
        c1 = cnt1[i]
        c2 = cnt2[i]
        mx = c1 if c1 > c2 else c2
        if mx <= 1:
            continue
        if c1 > c2:
            pref = "1:"
        elif c2 > c1:
            pref = "2:"
        else:
            pref = "=:"
        letter = chr(97 + i) * mx
        groups.append((mx, pref + letter))

    groups.sort(key=lambda x: (-x[0], x[1]))
    return '/'.join(g for _, g in groups)


