SIZE = 8

# build transition matrices for a single bit (0 or 1)
def build_T(bit):
    T = [[0] * SIZE for _ in range(SIZE)]
    for c in range(SIZE):
        for d in range(8):
            if ((c + d) & 1) == bit:
                nc = (c + d) >> 1
                T[c][nc] = (T[c][nc] + 1) % MOD
    return T

T0 = build_T(0)
T1 = build_T(1)

# matrix multiplication (A * B)
def mat_mul(A, B):
    C = [[0] * SIZE for _ in range(SIZE)]
    for i in range(SIZE):
        Ai = A[i]
        Ci = C[i]
        for k in range(SIZE):
            aik = Ai[k]
            if aik:
                Bk = B[k]
                for j in range(SIZE):
                    Ci[j] = (Ci[j] + aik * Bk[j]) % MOD
    return C

# precompute block matrices for all 8‑bit masks
B = [None] * 256
I = [[0] * SIZE for _ in range(SIZE)]
for i in range(SIZE):
    I[i][i] = 1

for mask in range(256):
    cur = I
    for i in range(8):
        bit = (mask >> i) & 1
        cur = mat_mul(cur, T1 if bit else T0)
    B[mask] = cur

# vector * matrix
def vec_mul(v, M):
    res = [0] * SIZE
    for i in range(SIZE):
        vi = v[i]
        if vi:
            Mi = M[i]
            for j in range(SIZE):
                res[j] = (res[j] + vi * Mi[j]) % MOD
    return res

