        print(sum(x * x for x in a))
        return

    def cost(L: int, p: int) -> int:
        q = L // p
        r = L % p
        return (p - r) * q * q + r * (q + 1) * (q + 1)

    def gain(L: int, p: int) -> int:
        if p >= L:
            return 0
        return cost(L, p) - cost(L, p + 1)

    heap = []
    for L in a:
        p = 1
        g = gain(L, p)
        heapq.heappush(heap, (-g, L, p))

    extra = k - n
    for _ in range(extra):
        neg_g, L, p = heapq.heappop(heap)
        p += 1
        g_new = gain(L, p)
        heapq.heappush(heap, (-g_new, L, p))

    total = 0
    while heap:
        _, L, p = heapq.heappop(heap)
        total += cost(L, p)

    print(total)

