    n = int(next(it))
    d = int(next(it))

    # a[0] = a[1] = 0, a[2]..a[n-2] are given, a[n-1] = 0
    a = [0] * n
    for i in range(1, n - 1):
        a[i] = int(next(it))

    x = [0] * n
    y = [0] * n
    for i in range(n):
        x[i] = int(next(it))
        y[i] = int(next(it))

    # pre‑compute all movement costs
    cost = [[0] * n for _ in range(n)]
    for i in range(n):
        for j in range(n):
            if i == j:
                continue
            cost[i][j] = d * (abs(x[i] - x[j]) + abs(y[i] - y[j]))

    # feasibility test for a given start time T
    def feasible(T: int) -> bool:
        best = [-1] * n
        best[0] = T
        heap = [(-T, 0)]          # max‑heap via negative values
        while heap:
            cur_neg, v = heapq.heappop(heap)
            cur = -cur_neg
            if cur < best[v]:
                continue
            if v == n - 1:
                return True
            for u in range(n):
                if u == v:
                    continue
                w = cost[v][u]
                if cur >= w:
                    nxt = cur - w
                    if u != n - 1:
                        nxt += a[u]
                    if nxt > best[u]:
                        best[u] = nxt
                        heapq.heappush(heap, (-nxt, u))
        return False

    high = cost[0][n - 1]          # direct move is always possible
    low = 0
    while low < high:
        mid = (low + high) // 2
        if feasible(mid):
            high = mid
        else:
            low = mid + 1
    print(low)


