    solve()

import sys

def solve() -> None:
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    n = int(next(it))
    T = int(next(it))

    # tasks_by_time[t] = list of interests of tasks whose required time is t
    tasks_by_time = [[] for _ in range(T + 1)]
    for _ in range(n):
        t = int(next(it))
        q = int(next(it))
        tasks_by_time[t].append(q)

    # sort decreasing – larger interests are considered first (helps a bit)
    for lst in tasks_by_time:
        lst.sort(reverse=True)

    INF_NEG = -10**18
    max_leaves = n                     # we never need more than n leaves
    dp = [INF_NEG] * (max_leaves + 1)
    dp[0] = 0

    # depths from deepest (T-1) down to 0
    for depth in range(T - 1, -1, -1):
        t_needed = T - depth           # tasks whose maximal depth == depth
        if t_needed <= T:
            for q in tasks_by_time[t_needed]:
                # 0/1 knapsack on leaf count
                for j in range(max_leaves, 0, -1):
                    if dp[j - 1] != INF_NEG:
                        val = dp[j - 1] + q
                        if val > dp[j]:
                            dp[j] = val

        # ---- capacity restriction for the current depth ----
        # at depth d we can have at most 2^d leaves, but n ≤ 1000,
        # so for d >= 10 the capacity already exceeds n.
        if depth < 10:
            cap = 1 << depth          # 2^depth
        else:
            cap = max_leaves
        if cap < max_leaves:
            for j in range(cap + 1, max_leaves + 1):
                dp[j] = INF_NEG

        # merge leaves when moving one level up (ceil(j/2) leaves become needed)
        nxt = [INF_NEG] * (max_leaves + 1)
        for j in range(max_leaves + 1):
            if dp[j] != INF_NEG:
                k = (j + 1) // 2       # ceil(j/2)
                if dp[j] > nxt[k]:
                    nxt[k] = dp[j]
        dp = nxt

    # after processing the root we may have 0 or 1 leaf left
    answer = max(dp[0], dp[1])
    print(answer)


