    solve()

import sys

def main() -> None:
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    n = int(next(it))
    a = [int(next(it)) for _ in range(n)]

    MAXV = 200000
    # smallest prime factor
    spf = list(range(MAXV + 1))
    for i in range(2, int(MAXV ** 0.5) + 1):
        if spf[i] == i:          # i is prime
            step = i
            start = i * i
            for j in range(start, MAXV + 1, step):
                if spf[j] == j:
                    spf[j] = i

    INF = 10 ** 9
    min1 = [INF] * (MAXV + 1)
    min2 = [INF] * (MAXV + 1)
    cnt_min1 = [0] * (MAXV + 1)
    freq = [0] * (MAXV + 1)

    for val in a:
        x = val
        # factorisation, collect exponents
        while x > 1:
            p = spf[x]
            e = 0
            while x % p == 0:
                x //= p
                e += 1
            # update structures for prime p
            freq[p] += 1
            if e < min1[p]:
                min2[p] = min1[p]
                min1[p] = e
                cnt_min1[p] = 1
            elif e == min1[p]:
                cnt_min1[p] += 1
            elif e < min2[p]:
                min2[p] = e

    ans = 1
    for p in range(2, MAXV + 1):
        if freq[p] == 0:
            continue
        zero_cnt = n - freq[p]
        if zero_cnt >= 2:
            use = 0
        elif zero_cnt == 1:
            use = min1[p]
        else:  # zero_cnt == 0
            if cnt_min1[p] >= 2:
                use = min1[p]
            else:
                use = min2[p] if min2[p] != INF else 0
        if use:
            ans *= pow(p, use)
    print(ans)


if __name__ == "__main__":
    main()
